spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 8000;
    var progress = (t % duration) / duration;

    var stage1 = '6 + (10 - 4) * 2';
    var stage2 = '6 + 6 * 2';
    var stage3 = '6 + 12';
    var stage4 = '18';

    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    // Positions
    var y1 = H * 0.25;
    var y2 = H * 0.42;
    var y3 = H * 0.58;
    var y4 = H * 0.75;

    // Phase boundaries
    var p1 = 0.25;
    var p2 = 0.50;
    var p3 = 0.75;

    // Stage 1: Always drawn
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '20px -apple-system, sans-serif';
    if (progress < p1) {
      // Highlight parentheses active
      ctx.fillStyle = '#FBBF24';
      ctx.font = 'bold 22px -apple-system, sans-serif';
      ctx.fillText(stage1, W / 2, y1);

      ctx.fillStyle = '#3B82F6';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('Step 1: Solve inside Parentheses (10 - 4)', W / 2, y1 + 25);
    } else {
      ctx.fillText(stage1, W / 2, y1);
    }

    // Stage 2
    if (progress >= p1) {
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '20px -apple-system, sans-serif';

      if (progress < p2) {
        ctx.fillStyle = '#FBBF24';
        ctx.font = 'bold 22px -apple-system, sans-serif';
        ctx.fillText(stage2, W / 2, y2);

        ctx.fillStyle = '#3B82F6';
        ctx.font = '12px -apple-system, sans-serif';
        ctx.fillText('Step 2: Multiply before adding (6 * 2)', W / 2, y2 + 25);
      } else {
        ctx.fillText(stage2, W / 2, y2);
      }
    }

    // Stage 3
    if (progress >= p2) {
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '20px -apple-system, sans-serif';

      if (progress < p3) {
        ctx.fillStyle = '#FBBF24';
        ctx.font = 'bold 22px -apple-system, sans-serif';
        ctx.fillText(stage3, W / 2, y3);

        ctx.fillStyle = '#3B82F6';
        ctx.font = '12px -apple-system, sans-serif';
        ctx.fillText('Step 3: Perform final Addition (6 + 12)', W / 2, y3 + 25);
      } else {
        ctx.fillText(stage3, W / 2, y3);
      }
    }

    // Stage 4 (Final result)
    if (progress >= p3) {
      var pulse = 1 + Math.sin(t * 0.01) * 0.06;
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold ' + Math.floor(32 * pulse) + 'px -apple-system, sans-serif';
      ctx.fillText(stage4, W / 2, y4);

      ctx.fillStyle = '#34D399';
      ctx.font = '14px -apple-system, sans-serif';
      ctx.fillText('Result = 18', W / 2, y4 + 30);
    }
  }
};
